import {
  type CSSProperties,
  type FocusEvent,
  forwardRef,
  type KeyboardEvent,
  useState,
} from 'react';
import { cls, useNamespace } from '../../utils';
import { type ComponentSize, useDisabled, useSize } from '../../config-provider';

export interface InputNumberProps {
  /** Controlled value. */
  value?: number;
  /** Initial value for the uncontrolled mode. */
  defaultValue?: number;
  /** Fired with the next value, or `null` when the field is empty. */
  onChange?: (value: number | null) => void;
  /** Minimum allowed value. */
  min?: number;
  /** Maximum allowed value. */
  max?: number;
  /** Increment / decrement step. */
  step?: number;
  /** Only allow values that are multiples of `step`. */
  stepStrictly?: boolean;
  /** Number of decimal places to keep. */
  precision?: number;
  /** Size. Falls back to the nearest ConfigProvider. */
  size?: ComponentSize;
  /** Disable the control. */
  disabled?: boolean;
  /** Make the field read-only: non-editable while still focusable, stepping disabled. */
  readonly?: boolean;
  /** Show the increase / decrease buttons. */
  controls?: boolean;
  /** Place both controls on the right, stacked. */
  controlsPosition?: 'right' | '';
  /** Placeholder text. */
  placeholder?: string;
  /** Native `name` attribute. */
  name?: string;
  /** Native `id` attribute. */
  id?: string;
  /** Accessible name for the field. */
  'aria-label'?: string;
  /** Fired on focus. */
  onFocus?: (event: FocusEvent<HTMLInputElement>) => void;
  /** Fired on blur, after the value has been clamped. */
  onBlur?: (event: FocusEvent<HTMLInputElement>) => void;
  /** Extra class on the root element. */
  className?: string;
  /** Extra style on the root element. */
  style?: CSSProperties;
}

function MinusIcon() {
  return (
    <svg viewBox="0 0 1024 1024" xmlns="http://www.w3.org/2000/svg">
      <path fill="currentColor" d="M128 480h768a32 32 0 1 1 0 64H128a32 32 0 0 1 0-64z" />
    </svg>
  );
}

function PlusIcon() {
  return (
    <svg viewBox="0 0 1024 1024" xmlns="http://www.w3.org/2000/svg">
      <path
        fill="currentColor"
        d="M480 480V128a32 32 0 0 1 64 0v352h352a32 32 0 1 1 0 64H544v352a32 32 0 1 1-64 0V544H128a32 32 0 0 1 0-64h352z"
      />
    </svg>
  );
}

function toPrecision(value: number, precision?: number): number {
  if (precision === undefined) return value;
  const factor = 10 ** precision;
  return Math.round(value * factor) / factor;
}

export const InputNumber = forwardRef<HTMLInputElement, InputNumberProps>(function InputNumber(
  props,
  ref,
) {
  const {
    value,
    defaultValue,
    onChange,
    min = -Infinity,
    max = Infinity,
    step = 1,
    stepStrictly = false,
    precision,
    size: sizeProp,
    disabled: disabledProp,
    readonly = false,
    controls = true,
    controlsPosition = '',
    placeholder,
    name,
    id,
    'aria-label': ariaLabel,
    onFocus,
    onBlur,
    className,
    style,
  } = props;

  const ns = useNamespace('input-number');
  const size = useSize(sizeProp);
  const disabled = useDisabled(disabledProp);

  const isControlled = value !== undefined;
  const [inner, setInner] = useState<number | null>(defaultValue ?? null);
  const current = isControlled ? value : inner;

  const clamp = (raw: number): number => {
    let next = raw;
    if (stepStrictly) next = Math.round(next / step) * step;
    next = toPrecision(next, precision);
    if (next < min) next = min;
    if (next > max) next = max;
    return next;
  };

  const update = (next: number | null) => {
    if (!isControlled) setInner(next);
    onChange?.(next);
  };

  const handleStep = (direction: 1 | -1) => {
    if (disabled || readonly) return;
    const base = current ?? 0;
    update(clamp(base + direction * step));
  };

  const handleInput = (raw: string) => {
    if (raw === '') {
      update(null);
      return;
    }
    const parsed = Number(raw);
    if (Number.isNaN(parsed)) return;
    update(parsed);
  };

  const handleKeyDown = (event: KeyboardEvent<HTMLInputElement>) => {
    if (disabled || readonly) return;
    if (event.key === 'ArrowUp') {
      event.preventDefault();
      handleStep(1);
    } else if (event.key === 'ArrowDown') {
      event.preventDefault();
      handleStep(-1);
    }
  };

  const handleBlur = (event: FocusEvent<HTMLInputElement>) => {
    if (current !== null && current !== undefined) {
      const clamped = clamp(current);
      if (clamped !== current) update(clamped);
    }
    onBlur?.(event);
  };

  const decreaseDisabled =
    disabled || readonly || (current !== null && current !== undefined && current <= min);
  const increaseDisabled =
    disabled || readonly || (current !== null && current !== undefined && current >= max);

  const displayValue =
    current === null || current === undefined
      ? ''
      : precision !== undefined
        ? current.toFixed(precision)
        : String(current);

  const classes = cls(
    ns.b(),
    size !== 'default' && ns.m(size),
    ns.is('disabled', disabled),
    ns.is('without-controls', !controls),
    controls && controlsPosition === 'right' && ns.is('controls-right'),
    className,
  );

  const decreaseButton = (
    <span
      role="button"
      aria-label="Decrease"
      aria-disabled={decreaseDisabled || undefined}
      tabIndex={-1}
      className={cls(ns.e('decrease'), decreaseDisabled && ns.is('disabled'))}
      onClick={() => {
        if (!decreaseDisabled) handleStep(-1);
      }}
    >
      <MinusIcon />
    </span>
  );

  const increaseButton = (
    <span
      role="button"
      aria-label="Increase"
      aria-disabled={increaseDisabled || undefined}
      tabIndex={-1}
      className={cls(ns.e('increase'), increaseDisabled && ns.is('disabled'))}
      onClick={() => {
        if (!increaseDisabled) handleStep(1);
      }}
    >
      <PlusIcon />
    </span>
  );

  return (
    <div className={classes} style={style}>
      {controls && controlsPosition !== 'right' && decreaseButton}
      <div className={ns.e('wrapper')}>
        <input
          ref={ref}
          className={ns.e('inner')}
          type="text"
          role="spinbutton"
          inputMode="decimal"
          value={displayValue}
          placeholder={placeholder}
          disabled={disabled}
          readOnly={readonly}
          name={name}
          id={id}
          aria-label={ariaLabel}
          aria-valuenow={current ?? undefined}
          aria-valuemin={min === -Infinity ? undefined : min}
          aria-valuemax={max === Infinity ? undefined : max}
          aria-disabled={disabled || undefined}
          onChange={(event) => handleInput(event.target.value)}
          onKeyDown={handleKeyDown}
          onFocus={onFocus}
          onBlur={handleBlur}
        />
      </div>
      {controls && controlsPosition !== 'right' && increaseButton}
      {controls && controlsPosition === 'right' && (
        <span className={ns.e('controls')}>
          {increaseButton}
          {decreaseButton}
        </span>
      )}
    </div>
  );
});

.ec-input-number {
  --ec-input-number-text-color: var(--ec-text-color-regular);
  --ec-input-number-border-color: var(--ec-border-color);
  --ec-input-number-hover-border-color: var(--ec-border-color-hover);
  --ec-input-number-focus-border-color: var(--ec-color-primary);
  --ec-input-number-bg-color: var(--ec-fill-color-blank);
  --ec-input-number-control-color: var(--ec-text-color-secondary);
  --ec-input-number-border-radius: var(--ec-border-radius-base);
  --ec-input-number-height: var(--ec-component-size);
  --ec-input-number-font-size: var(--ec-font-size-base);

  position: relative;
  display: inline-flex;
  align-items: stretch;
  box-sizing: border-box;
  width: 150px;
  height: var(--ec-input-number-height);
  font-size: var(--ec-input-number-font-size);
  line-height: var(--ec-input-number-height);
}

.ec-input-number__wrapper {
  display: inline-flex;
  flex-grow: 1;
  align-items: center;
  box-sizing: border-box;
  width: 100%;
  height: 100%;
  background-color: var(--ec-input-number-bg-color);
  border-radius: var(--ec-input-number-border-radius);
  transition: var(--ec-transition-box-shadow, var(--ec-transition-all));
  box-shadow: 0 0 0 1px var(--ec-input-number-border-color) inset;
}

.ec-input-number__wrapper:hover {
  box-shadow: 0 0 0 1px var(--ec-input-number-hover-border-color) inset;
}

.ec-input-number__wrapper:focus-within {
  box-shadow: 0 0 0 1px var(--ec-input-number-focus-border-color) inset;
}

.ec-input-number__inner {
  width: 100%;
  min-width: 0;
  height: 100%;
  padding: 0 11px;
  margin: 0;
  font-family: inherit;
  font-size: inherit;
  line-height: inherit;
  text-align: center;
  color: var(--ec-input-number-text-color);
  background: none;
  border: none;
  outline: none;
  appearance: textfield;
  -moz-appearance: textfield;
}

.ec-input-number__inner::-webkit-outer-spin-button,
.ec-input-number__inner::-webkit-inner-spin-button {
  margin: 0;
  appearance: none;
  -webkit-appearance: none;
}

.ec-input-number__decrease,
.ec-input-number__increase {
  position: relative;
  z-index: var(--ec-index-normal);
  display: inline-flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
  width: var(--ec-input-number-height);
  height: auto;
  font-size: var(--ec-font-size-base);
  color: var(--ec-input-number-control-color);
  background-color: var(--ec-fill-color-light);
  cursor: pointer;
  user-select: none;
  transition: var(--ec-transition-color);
}

.ec-input-number__decrease svg,
.ec-input-number__increase svg {
  width: 1em;
  height: 1em;
}

.ec-input-number__decrease {
  border-radius: var(--ec-input-number-border-radius) 0 0 var(--ec-input-number-border-radius);
  box-shadow: 0 0 0 1px var(--ec-input-number-border-color) inset;
}

.ec-input-number__increase {
  border-radius: 0 var(--ec-input-number-border-radius) var(--ec-input-number-border-radius) 0;
  box-shadow: 0 0 0 1px var(--ec-input-number-border-color) inset;
}

.ec-input-number__decrease:hover:not(.is-disabled),
.ec-input-number__increase:hover:not(.is-disabled) {
  color: var(--ec-color-primary);
}

.ec-input-number__decrease.is-disabled,
.ec-input-number__increase.is-disabled {
  color: var(--ec-disabled-text-color);
  cursor: not-allowed;
}

/* Squared inner corners between controls and field */
.ec-input-number:not(.is-controls-right) .ec-input-number__wrapper {
  border-radius: 0;
}

/* ---- Disabled ---- */
.ec-input-number.is-disabled .ec-input-number__wrapper {
  background-color: var(--ec-disabled-bg-color);
  box-shadow: 0 0 0 1px var(--ec-disabled-border-color) inset;
  cursor: not-allowed;
}

.ec-input-number.is-disabled .ec-input-number__inner {
  color: var(--ec-disabled-text-color);
  -webkit-text-fill-color: var(--ec-disabled-text-color);
  cursor: not-allowed;
}

.ec-input-number.is-disabled .ec-input-number__decrease,
.ec-input-number.is-disabled .ec-input-number__increase {
  background-color: var(--ec-disabled-bg-color);
}

/* ---- Without controls ---- */
.ec-input-number.is-without-controls .ec-input-number__wrapper {
  border-radius: var(--ec-input-number-border-radius);
}

.ec-input-number.is-without-controls .ec-input-number__inner {
  text-align: left;
}

/* ---- Controls on the right ---- */
.ec-input-number.is-controls-right .ec-input-number__wrapper {
  border-radius: var(--ec-input-number-border-radius);
}

.ec-input-number.is-controls-right .ec-input-number__inner {
  padding-right: calc(var(--ec-input-number-height) + 6px);
  text-align: left;
}

.ec-input-number__controls {
  position: absolute;
  top: 1px;
  right: 1px;
  bottom: 1px;
  display: flex;
  flex-direction: column;
  width: calc(var(--ec-input-number-height) - 2px);
}

.ec-input-number.is-controls-right .ec-input-number__increase,
.ec-input-number.is-controls-right .ec-input-number__decrease {
  width: 100%;
  height: 50%;
  font-size: var(--ec-font-size-extra-small);
  border-radius: 0;
}

.ec-input-number.is-controls-right .ec-input-number__increase {
  border-top-right-radius: var(--ec-input-number-border-radius);
  box-shadow: 0 0 0 1px var(--ec-input-number-border-color) inset;
}

.ec-input-number.is-controls-right .ec-input-number__decrease {
  border-bottom-right-radius: var(--ec-input-number-border-radius);
  box-shadow: 0 0 0 1px var(--ec-input-number-border-color) inset;
}

/* ---- Sizes ---- */
.ec-input-number--large {
  --ec-input-number-height: var(--ec-component-size-large);
  --ec-input-number-font-size: var(--ec-font-size-medium);
}

.ec-input-number--small {
  --ec-input-number-height: var(--ec-component-size-small);
  --ec-input-number-font-size: var(--ec-font-size-extra-small);
  width: 130px;
}
